def login_redirect(user_input_url, allowlist):
    # Define a default redirect URL
    default_redirect_url = '/home'

    # Check if the user_input_url is in the allowlist
    if user_input_url in allowlist:
        redirect_url = user_input_url
    else:
        redirect_url = default_redirect_url

    # Perform the redirect
    return redirect_url

